    // --- Damage Calculation (Client-side) ---

    public float CalculateOutgoingDamage(float enemyDefense)
    {
        float totalAttack = GetTotalAttack();
        float baseDamage = totalAttack * currentDamageMultiplier;

        // Critical hit check
        float totalCritChance = GetTotalCritChance();
        lastHitWasCritical = UnityEngine.Random.value <= totalCritChance;

        if (lastHitWasCritical)
        {
            baseDamage *= playerStats.critMultiplier;
        }

        // Apply enemy defense reduction
        float damageReduction = enemyDefense / (enemyDefense + 100f);
        float finalDamage = baseDamage * (1f - damageReduction);

        // Level scaling
        finalDamage *= 1f + (playerStats.level - 1) * 0.05f;

        finalDamage = Mathf.Max(1f, finalDamage);
        lastDamageDealt = finalDamage;

        return finalDamage;
    }

    public float CalculateIncomingDamage(float incomingRawDamage)
    {
        float totalDefense = GetTotalDefense();
        float damageReduction = (totalDefense * currentDefenseMultiplier) / ((totalDefense * currentDefenseMultiplier) + 100f);
        float finalDamage = incomingRawDamage * (1f - damageReduction);

        finalDamage = Mathf.Max(1f, finalDamage);
        lastDamageReceived = finalDamage;

        return finalDamage;
    }

    public void TakeDamage(float rawDamage)
    {
        float actualDamage = CalculateIncomingDamage(rawDamage);
        playerStats.currentHealth -= actualDamage;
        playerStats.currentHealth = Mathf.Clamp(playerStats.currentHealth, 0f, playerStats.maxHealth);

        OnHealthChanged?.Invoke(playerStats.currentHealth);

        if (playerStats.currentHealth <= 0f)
        {
            OnPlayerDied?.Invoke();
        }

        SavePlayerData();
    }

    public void Heal(float amount)
    {
        playerStats.currentHealth += amount;
        playerStats.currentHealth = Mathf.Clamp(playerStats.currentHealth, 0f, GetTotalMaxHealth());

        OnHealthChanged?.Invoke(playerStats.currentHealth);
        SavePlayerData();
    }

    public void FullHeal()
    {
        playerStats.currentHealth = GetTotalMaxHealth();
        OnHealthChanged?.Invoke(playerStats.currentHealth);
        SavePlayerData();
    }

    // --- Stats Calculation ---

    public float GetTotalAttack()
    {
        float total = playerStats.baseAttack;
        foreach (string itemId in playerStats.equippedItems)
        {
            ShopItem item = shopInventory.Find(i => i.itemId == itemId);
            if (item != null)
            {
                total += item.attackBonus;
            }
        }
        return total;
    }

    public float GetTotalDefense()
    {
        float total = playerStats.baseDefense;
        foreach (string itemId in playerStats.equippedItems)
        {
            ShopItem item = shopInventory.Find(i => i.itemId == itemId);
            if (item != null)
            {
                total += item.defenseBonus;
            }
        }
        return total;
    }

    public float GetTotalMaxHealth()
    {
        float total = playerStats.maxHealth;
        foreach (string itemId in playerStats.equippedItems)
        {
            ShopItem item = shopInventory.Find(i => i.itemId == itemId);
            if (item != null)
            {
                total += item.healthBonus;
            }
        }
        return total;
    }

    public float GetTotalCritChance()
    {
        float total = playerStats.critChance;
        foreach (string itemId in playerStats.equippedItems)
        {
            ShopItem item = shopInventory.Find(i => i.itemId == itemId);
            if (item != null)
            {
                total += item.critChanceBonus;
            }
        }
        return Mathf.Clamp01(total);
    }

    // --- Shop / Purchase System (Client-side price calculation) ---

    public int CalculateItemPrice(string itemId, bool usePremium = false)
    {
        ShopItem item = shopInventory.Find(i => i.itemId == itemId);
        if (item == null) return -1;

        int basePrice = usePremium ? item.premiumPrice : item.price;

        // Apply discount
        float discount = 1f - (discountPercentage / 100f);
        int finalPrice = Mathf.RoundToInt(basePrice * discount);
        finalPrice = Mathf.Max(0, finalPrice);

        currentItemPrice = finalPrice;
        return finalPrice;
    }

    public bool CanAffordItem(string itemId, bool usePremium = false)
    {
        int price = CalculateItemPrice(itemId, usePremium);
        if (price < 0) return false;

        if (usePremium)
        {
            return playerStats.premiumCurrency >= price;
        }
        else
        {
            return playerStats.currency >= price;
        }
    }

    public bool PurchaseItem(string itemId, bool usePremium = false)
    {
        ShopItem item = shopInventory.Find(i => i.itemId == itemId);
        if (item == null)
        {
            OnPurchaseFailed?.Invoke("Item not found: " + itemId);
            return false;
        }

        // Check if already owned (non-consumable)
        if (!IsConsumable(itemId) && playerStats.ownedItems.Contains(itemId))
        {
            OnPurchaseFailed?.Invoke("Item already owned: " + item.itemName);
            return false;
        }

        // Check premium-only
        if (item.isPremiumOnly && !usePremium)
        {
            usePremium = true;
        }

        int price = CalculateItemPrice(itemId, usePremium);

        if (!CanAffordItem(itemId, usePremium))
        {
            OnPurchaseFailed?.Invoke("Not enough " + (usePremium ? "premium " : "") + "currency for " + item.itemName);
            return false;
        }

        // Deduct currency
        if (usePremium)
        {
            playerStats.premiumCurrency -= price;
            OnPremiumCurrencyChanged?.Invoke(playerStats.premiumCurrency);
        }
        else
        {
            playerStats.currency -= price;
            OnCurrencyChanged?.Invoke(playerStats.currency);
        }

        // Apply item effects
        if (IsConsumable(itemId))
        {
            ApplyConsumable(itemId);
        }
        else
        {
            playerStats.ownedItems.Add(itemId);
        }

        OnItemPurchased?.Invoke(itemId);
        SavePlayerData();

        Debug.Log($"Purchased {item.itemName} for {price} {(usePremium ? "premium" : "regular")} currency.");
        return true;
    }

    private bool IsConsumable(string itemId)
    {
        return itemId.StartsWith("potion_");
    }

    private void ApplyConsumable(string itemId)
    {
        switch (itemId)
        {
            case "potion_health":
                Heal(50f);
                break;
            case "potion_mega_health":
                FullHeal();
                break;
        }
    }

    public bool EquipItem(string itemId)
    {
        if (!playerStats.ownedItems.Contains(itemId))
        {
            Debug.LogWarning("Cannot equip item not owned: " + itemId);
            return false;
        }

        if (playerStats.equippedItems.Contains(itemId))
        {
            Debug.LogWarning("Item already equipped: " + itemId);
            return false;
        }

        playerStats.equippedItems.Add(itemId);

        // Update max health if health bonus
        ShopItem item = shopInventory.Find(i => i.itemId == itemId);
        if (item != null && item.healthBonus > 0)
        {
            playerStats.currentHealth = Mathf.Clamp(playerStats.currentHealth, 0f, GetTotalMaxHealth());
        }

        SavePlayerData();
        return true;
    }

    public bool UnequipItem(string itemId)
    {
        if (!playerStats.equippedItems.Contains(itemId))
        {
            Debug.LogWarning("Item not equipped: " + itemId);
            return false;
        }

        playerStats.equippedItems.Remove(itemId);

        // Clamp health to new max
        float newMaxHealth = GetTotalMaxHealth();
        playerStats.currentHealth = Mathf.Clamp(playerStats.currentHealth, 0f, newMaxHealth);
        OnHealthChanged?.Invoke(playerStats.currentHealth);

        SavePlayerData();
        return true;
    }

    // --- Currency Management ---

    public void AddCurrency(int amount)
    {
        playerStats.currency += amount;
        OnCurrencyChanged?.Invoke(playerStats.currency);
        SavePlayerData();
    }

    public void AddPremiumCurrency(int amount)
    {
        playerStats.premiumCurrency += amount;
        OnPremiumCurrencyChanged?.Invoke(playerStats.premiumCurrency);
        SavePlayerData();
    }

    public void SetDiscount(float percentage)
    {
        discountPercentage = Mathf.Clamp(percentage, 0f, 100f);
    }

    // --- Level System ---

    public void LevelUp()
    {
        playerStats.level++;
        playerStats.baseAttack += 2f;
        playerStats.baseDefense += 1f;
        playerStats.maxHealth += 10f;
        playerStats.currentHealth = GetTotalMaxHealth();

        OnHealthChanged?.Invoke(playerStats.currentHealth);
        SavePlayerData();

        Debug.Log($"Player leveled up to {playerStats.level}!");
    }

    // --- IAP Integration Hooks ---

    public void OnIAPPurchaseComplete(string productId)
    {
        switch (productId)
        {
            case "com.game.gems_100":
                AddPremiumCurrency(100);
                break;
            case "com.game.gems_500":
                AddPremiumCurrency(500);
                break;
            case "com.game.gems_1200":
                AddPremiumCurrency(1200);
                break;
            case "com.game.gold_1000":
                AddCurrency(1000);
                break;
            case "com.game.gold_5000":
                AddCurrency(5000);
                break;
            case "com.game.starter_pack":
                AddCurrency(2000);
                AddPremiumCurrency(200);
                PurchaseItem("sword_flame", false);
                break;
            default:
                Debug.LogWarning("Unknown IAP product: " + productId);
                break;
        }
    }

    // --- Save / Load ---

    public void SavePlayerData()
    {
        string json = JsonUtility.ToJson(playerStats);
        PlayerPrefs.SetString("PlayerStats", json);
        PlayerPrefs.Save();
    }

    public void LoadPlayerData()
    {
        if (PlayerPrefs.HasKey("PlayerStats"))
        {
            string json = PlayerPrefs.GetString("PlayerStats");
            JsonUtility.FromJsonOverwrite(json, playerStats);
        }
    }

    public void ResetPlayerData()
    {
        playerStats = new PlayerStats();
        PlayerPrefs.DeleteKey("PlayerStats");
        PlayerPrefs.Save();

        OnHealthChanged?.Invoke(playerStats.currentHealth);
        OnCurrencyChanged?.Invoke(playerStats.currency);
        OnPremiumCurrencyChanged?.Invoke(playerStats.premiumCurrency);
    }
}

public class PlayerController : MonoBehaviour
{
    public float moveSpeed = 5f;
    public float attackRange = 2f;
    public float attackCooldown = 1f;

    private float lastAttackTime = 0f;
    private GameManager gameManager;

    private void Start()
    {
        gameManager = GameManager.Instance;

        gameManager.OnHealthChanged += OnHealthChanged;
        gameManager.OnPlayerDied += OnPlayerDied;
        gameManager.OnCurrencyChanged += OnCurrencyChanged;
    }

    private void OnDestroy()
    {
        if (gameManager != null)
        {
            gameManager.OnHealthChanged -= OnHealthChanged;
            gameManager.OnPlayerDied -= OnPlayerDied;
            gameManager.OnCurrencyChanged -= OnCurrencyChanged;
        }
    }

    private void Update()
    {
        HandleMovementInput();
        HandleAttackInput();
    }

    private void HandleMovementInput()
    {
        // Touch / joystick input for mobile
        float horizontal = Input.GetAxis("Horizontal");
        float vertical = Input.GetAxis("Vertical");

        Vector3 movement = new Vector3(horizontal, 0f, vertical).normalized;
        transform.Translate(movement * moveSpeed * Time.deltaTime, Space.World);

        if (movement.magnitude > 0.1f)
        {
            transform.rotation = Quaternion.LookRotation(movement);
        }
    }

    private void HandleAttackInput()
    {
        if (Input.GetButtonDown("Fire1") && Time.time - lastAttackTime >= attackCooldown)
        {
            PerformAttack();
            lastAttackTime = Time.time;
        }
    }

    private void PerformAttack()
    {
        Collider[] hitColliders = Physics.OverlapSphere(transform.position, attackRange);
        foreach (Collider hit in hitColliders)
        {
            EnemyController enemy = hit.GetComponent<EnemyController>();
            if (enemy != null)
            {
                float damage = gameManager.CalculateOutgoingDamage(enemy.defense);
                enemy.TakeDamage(damage);

                if (gameManager.lastHitWasCritical)
                {
                    Debug.Log($"CRITICAL HIT! Dealt {damage:F1} damage!");
                }
            }
        }
    }

    private void OnHealthChanged(float newHealth)
    {
        Debug.Log($"Player health: {newHealth:F1}/{gameManager.GetTotalMaxHealth():F1}");
    }

    private void OnPlayerDied()
    {
        Debug.Log("Player has died!");
        // Respawn logic, show revive ad, etc.
    }

    private void OnCurrencyChanged(int newAmount)
    {
        Debug.Log($"Currency: {newAmount}");
    }

    private void OnTriggerEnter(Collider other)
    {
        // Pickup coins
        CoinPickup coin = other.GetComponent<CoinPickup>();
        if (coin != null)
        {
            gameManager.AddCurrency(coin.value);
            Destroy(other.gameObject);
        }
    }
}

public class EnemyController : MonoBehaviour
{
    public float maxHealth = 50f;
    public float currentHealth = 50f;
    public float attackDamage = 15f;
    public float defense = 5f;
    public float attackCooldown = 2f;
    public float attackRange = 2.5f;
    public float detectionRange = 10f;
    public float moveSpeed = 3f;
    public int currencyReward = 50;
    public int experienceReward = 25;

    private float lastAttackTime = 0f;
    private Transform playerTransform;
    private GameManager gameManager;

    private void Start()
    {
        gameManager = GameManager.Instance;
        currentHealth = maxHealth;

        GameObject player = GameObject.FindGameObjectWithTag("Player");
        if (player != null)
        {
            playerTransform = player.transform;
        }
    }

    private void Update()
    {
        if (playerTransform == null) return;

        float distanceToPlayer = Vector3.Distance(transform.position, playerTransform.position);

        if (distanceToPlayer <= attackRange && Time.time - lastAttackTime >= attackCooldown)
        {
            AttackPlayer();
            lastAttackTime = Time.time;
        }
        else if (distanceToPlayer <= detectionRange && distanceToPlayer > attackRange)
        {
            MoveTowardsPlayer();
        }
    }

    private void MoveTowardsPlayer()
    {
        Vector3 direction = (playerTransform.position - transform.position).normalized;
        transform.Translate(direction * moveSpeed * Time.deltaTime, Space.World);
        transform.LookAt(playerTransform);
    }

    private void AttackPlayer()
    {
        gameManager.TakeDamage(attackDamage);
        Debug.Log($"Enemy dealt {gameManager.lastDamageReceived:F1} damage to player.");
    }

    public void TakeDamage(float damage)
    {
        currentHealth -= damage;
        currentHealth = Mathf.Max(0f, currentHealth);

        if (currentHealth <= 0f)
        {
            Die();
        }
    }

    private void Die()
    {
        gameManager.AddCurrency(currencyReward);
        Debug.Log($"Enemy killed! +{currencyReward} currency.");
        Destroy(gameObject);
    }
}

