public class ShopUI : MonoBehaviour
{
    private GameManager gameManager;

    private void Start()
    {
        gameManager = GameManager.Instance;
    }

    public void OnBuyButtonPressed(string itemId)
    {
        bool success = gameManager.PurchaseItem(itemId, false);
        if (success)
        {
            Debug.Log("Purchase successful!");
            RefreshUI();
        }
    }

    public void OnBuyPremiumButtonPressed(string itemId)
    {
        bool success = gameManager.PurchaseItem(itemId, true);
        if (success)
        {
            Debug.Log("Premium purchase successful!");
            RefreshUI();
        }
    }

    public void OnEquipButtonPressed(string itemId)
    {
        if (gameManager.playerStats.equippedItems.Contains(itemId))
        {
            gameManager.UnequipItem(itemId);
        }
        else
        {
            gameManager.EquipItem(itemId);
        }
        RefreshUI();
    }

    public void RefreshUI()
    {
        foreach (ShopItem item in gameManager.shopInventory)
        {
            int price = gameManager.CalculateItemPrice(item.itemId, item.isPremiumOnly);
            bool owned = gameManager.playerStats.ownedItems.Contains(item.itemId);
            bool equipped = gameManager.playerStats.equippedItems.Contains(item.itemId);
            bool canAfford = gameManager.CanAffordItem(item.itemId, item.isPremiumOnly);

            Debug.Log($"[{item.itemName}] Price: {price} | Owned: {owned} | Equipped: {equipped} | Can Afford: {canAfford}");
        }

        Debug.Log($"Gold: {gameManager.playerStats.currency} | Gems: {gameManager.playerStats.premiumCurrency}");
        Debug.Log($"ATK: {gameManager.GetTotalAttack():F1} | DEF: {gameManager.GetTotalDefense():F1} | HP: {gameManager.playerStats.currentHealth:F1}/{gameManager.GetTotalMaxHealth():F1} | CRIT: {gameManager.GetTotalCritChance() * 100f:F1}%");
    }
}

